const ITEM_BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const RUNE_BLOCK_SIZE = 3;
const RUNE_BLOCK_BASE_PREMIUM = 60;

const premiumFor = (totalBase: number): number =>
  totalBase + Math.ceil(totalBase * FIRST_INSURANCE_RATE) + PROCESSING_FEE;

const baseFor = (item: { type: string }): number => ITEM_BASE_PREMIUMS[item.type];

const isRuneBlock = (items: Array<{ type: string }>): boolean =>
  items.length === RUNE_BLOCK_SIZE && items.every((i) => i.type === "rune");

const totalBaseFor = (items: Array<{ type: string }>): number => {
  if (isRuneBlock(items)) return RUNE_BLOCK_BASE_PREMIUM;
  return items.reduce((sum, item) => sum + baseFor(item), 0);
};
